import SwiftUI

struct ContentView: View {
    @State private var apiResponse: String = "API Response: Waiting..."
    @State private var legacyResponse: String = "Legacy Response: Waiting..."

    var body: some View {
        VStack(spacing: 20) {
            Text("Network Requests Example")
                .font(.largeTitle)
                .padding(.bottom, 20)

            Spacer()

            Button("Fetch from API (HTTPS)") {
                // Use a real endpoint for your API, e.g., "https://api.example.com/status"
                fetchData(from: "https://api.example.com/data", for: .api)
            }
            .buttonStyle(.borderedProminent)

            Text(apiResponse)
                .font(.body)
                .padding()
                .background(Color.gray.opacity(0.2))
                .cornerRadius(8)
                .multilineTextAlignment(.center)

            Divider()
                .padding(.vertical)

            Button("Fetch from Legacy (HTTP)") {
                // Use a real endpoint for your legacy system, e.g., "http://legacy.internal/health"
                fetchData(from: "http://legacy.internal/status", for: .legacy)
            }
            .buttonStyle(.borderedProminent)

            Text(legacyResponse)
                .font(.body)
                .padding()
                .background(Color.gray.opacity(0.2))
                .cornerRadius(8)
                .multilineTextAlignment(.center)

            Spacer()
        }
        .padding()
    }

    enum RequestType {
        case api
        case legacy
    }

    private func fetchData(from urlString: String, for type: RequestType) {
        guard let url = URL(string: urlString) else {
            updateResponse(for: type, with: "Error: Invalid URL")
            return
        }

        URLSession.shared.dataTask(with: url) { data, response, error in
            DispatchQueue.main.async {
                if let error = error {
                    print("Request \(urlString) failed with error: \(error.localizedDescription)")
                    updateResponse(for: type, with: "Error: \(error.localizedDescription)")
                    return
                }

                guard let httpResponse = response as? HTTPURLResponse else {
                    print("Request \(urlString) received non-HTTP response.")
                    updateResponse(for: type, with: "Error: No HTTP response")
                    return
                }

                if httpResponse.statusCode >= 200 && httpResponse.statusCode < 300 {
                    if let data = data, let str = String(data: data, encoding: .utf8) {
                        updateResponse(for: type, with: "Success (\(httpResponse.statusCode)): \(str.prefix(100))...")
                    } else {
                        updateResponse(for: type, with: "Success (\(httpResponse.statusCode)): No data or unreadable data")
                    }
                } else {
                    updateResponse(for: type, with: "HTTP Error: \(httpResponse.statusCode)")
                }
            }
        }.resume()
    }

    private func updateResponse(for type: RequestType, with message: String) {
        switch type {
        case .api:
            apiResponse = "API Response: \(message)"
        case .legacy:
            legacyResponse = "Legacy Response: \(message)"
        }
    }
}

